var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"同時刻","ENG":"Meanwhile","TWN":"同一時間"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>로터스</color> 아마니 밸리\\n관리국 본부, 제3부설 격납고","JPN":"管理局直轄都市<color=#ffd34c>ロータス</color>アマニーバレー\\n管理局本部、第3付属格納庫","ENG":"Administration Direct Control City, <color=#ffd34c>Lotus</color>, Amani Valley\\nAdministration HQ, Auxiliary Hangar 3","TWN":"管理局直轄市 <color=#ffd34c>洛德斯</color> 阿瑪尼山谷\\n管理局總部附設第3機庫"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"퓨처 앳 워에 관한 중요한 문제라더니…….","JPN":"フューチャーアットウォーに関する重要な問題と言うから来てみたら……","ENG":"So this Future-at-War matter you said was important...","TWN":"說是關於天啟兵器的重要問題……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"최고 관리자, 당신 설마… 저것 때문에 나를 이리로 부른 거였어?","JPN":"最高管理者、まさか……あれのために呼んだのか？","ENG":"Supreme Administrator, don't tell me... this is why you called me here?","TWN":"最高管理者，難道……你是因為那個才把我叫到這裡來的嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다네. 자네를 이곳에 부른 첫번째 이유는…….","JPN":"ああ。君をここに呼んだ1つ目の理由は……","ENG":"That is correct. The first reason I summoned you here is...","TWN":"是的。找你到這裡的第一個原因是……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>코핀 컴퍼니 압류 대상 9호</color>의 사용허가를 받기 위함이었네.","JPN":"<color=#ffd34c>コフィンカンパニー差し押さえ対象9号</color>の使用許可を出してもらうためだ。","ENG":"...to obtain authorization to use <color=#ffd34c>Coffin Company Seized Asset No. 9</color>.","TWN":"希望得到<color=#ffd34c>科芬公司扣押物件第9號</color>的使用許可。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하하하! 안녕하신가…! 모두 잘 부탁한다네……!","JPN":"ははは！　久しぶりだな……！　皆よろしく頼むぞ！","ENG":"Ha ha ha! Greetings...! I look forward to working with you all...!","TWN":"哈哈哈！你們好……！請大家多多關照……！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_15"},{"id":"L16_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하도 오랜만에 움직여서 그런지, 이거 온몸이 삐걱거리는구만……!","JPN":"久しぶりすぎるせいか、全身がギクシャクするな……！","ENG":"Been so long since I moved, my whole frame creaks with every step...!","TWN":"可能是因為太久沒動，渾身關節都在嘎吱作響……！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_07"},{"id":"L17_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"고작 압류품의 사용 허가를 받으려고, 시니어를 여기까지 불렀다고?","JPN":"たかが差し押さえ品の使用許可程度で、シニアをここまで呼び出しただと？","ENG":"You dragged a Senior all the way out here just to authorize a seized asset?","TWN":"只因為要拿到使用扣押物品的許可，竟然把Senior叫到這裡來？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……웃기지 마, 당신.","JPN":"……ふざけるなよ。","ENG":"...Don't make me laugh.","TWN":"……你在跟我開玩笑嗎！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"저 고철 덩어리를 또다시 내 눈 앞에 들이민 것 자체가 의도가 뻔하잖아?","JPN":"あの鉄くずを私の前に出してくることからして、意図が見え透いている！","ENG":"Parading that pile of scrap in front of me again makes your intent obvious enough.","TWN":"你又把那堆廢鐵放到我面前，意圖已經很明顯了不是嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당신 대체 뭐야? 날 모른다고 할 때는 언제고… 이제 와서 대체 무슨 짓거리야……?","JPN":"あなた、一体何のつもりだ？　私のことをよく知らないと言ってたくせに……今さら何をするつもりだ？","ENG":"What are you really after? First you pretended not to know me... and now this farce?","TWN":"你到底是什麼人？之前還說不認識我…現在又在搞什麼鬼……？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이거 미안하게 됐군, 르네 말루프 양.","JPN":"すまないな、ルネ・マルーフ君。","ENG":"My apologies, Renée Maalouf.","TWN":"真是抱歉了，芮妮·瑪盧夫。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네와 처음 만나게 된 뒤로, 자네에 대해서 알고 싶어졌거든.","JPN":"君と初めて出会ってから、君について知りたくなったのだ。","ENG":"After meeting you, I found myself wanting to know more about you.","TWN":"自從和你第一次見面後，我就很想瞭解你。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 내 나름대로 조사를 했네.","JPN":"それで、私なりに調べさせてもらったよ。","ENG":"So I made some inquiries on my own.","TWN":"所以我自己做了一些調查。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 최연소로 퓨처 앳 워 프로젝트에 발탁되었다는 것…….","JPN":"君が最年少でフューチャーアットウォーに抜擢されていたこと……","ENG":"I learned you were the youngest ever selected for the Future-at-War project...","TWN":"你是以最年輕的身份被選入天啟兵器計畫的……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 한 때 <color=#ffd34c>타이탄 프로젝트</color>에 참여했다는 것…….","JPN":"君がかつては<color=#ffd34c>タイタンプロジェクト</color>に参加していたこと……","ENG":"That you once participated in the <color=#ffd34c>Titan Project</color>...","TWN":"你曾經參與過<color=#ffd34c>泰坦計畫</color>……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 자네 팀이 무인 병기 전력을 혁신적으로 끌어올리기 위해.","JPN":"そして君のチームが無人兵器戦力を革新的に引き上げるために……","ENG":"And that your team sought to revolutionize unmanned weapons capability...","TWN":"而且為讓你的團隊能夠提升無人兵器的戰力，"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>체르노프</color> 박사에게 제안했었지만, 결국 반려되었던 타이탄의 <color=#ffd34c>시제안</color>이 존재한다는 것.","JPN":"<color=#ffd34c>チェルノフ</color>博士に提案したものの結局却下されてしまった、タイタンの<color=#ffd34c>試案</color>があるということが分かった。","ENG":"...by proposing a <color=#ffd34c>prototype</color> to Dr. <color=#ffd34c>Chernov</color>, though it was ultimately rejected.","TWN":"<color=#ffd34c>切爾諾夫</color>博士曾經提議過，但最終被否決的泰坦<color=#ffd34c>試製案</color>確實存在。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……<color=#ffd34c>주피터 플랜</color>.","JPN":"……<color=#ffd34c>ジュピタープラン</color>。","ENG":"...The <color=#ffd34c>Jupiter Plan</color>.","TWN":"……<color=#ffd34c>木星計畫</color>."},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"20년이나 지나 버린… 그 과거의 유산을, 이제 와서 나보고 재현하라고?","JPN":"20年も過ぎた……過去の遺産を、今更私に再現しろと？","ENG":"You want me... to recreate a relic from twenty years ago now?","TWN":"現在讓我重現那已經過去20年的遺產？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다네, 르네 양.","JPN":"そうだよ、ルネ君。","ENG":"That is correct, Renée.","TWN":"是的，芮妮。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 세계를 지키기 위해서 말이지.","JPN":"この世界を守るためにね。","ENG":"To safeguard this world.","TWN":"為了守護這個世界。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당신, 대체 무슨 생각이야!","JPN":"一体何を考えているんだ！","ENG":"What in the world are you thinking?!","TWN":"你到底在想什麼！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그때는 철이 없었지만, 이제는 나도 박사님께서 왜 그 시제안을 폐기했는지는 알아.","JPN":"あの頃の私はまだ未熟で、博士が何故あの試案を破棄したのか理解できなかった……だが今は分かる。","ENG":"I was naive back then, but now I understand why Dr. Chernov scrapped it.","TWN":"那時候我還不懂事，但現在我知道博士為什麼要放棄那個提案了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"주피터 플랜은 그저 이상론이었을 뿐, 실현 가능성 따위 없는 페이퍼 플랜이었으니까.","JPN":"ジュピタープランはただの理想論にすぎず、実現可能性などないペーパープランだった。","ENG":"The Jupiter Plan was nothing but idealism. It was an unworkable paper scheme.","TWN":"木星計畫不過是個理想論，只是個沒有實現可能性的紙上談兵而已。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하물며 당시에는 타이탄 프로젝트조차 불분명한 상황이었어.","JPN":"それに、当時はタイタンプロジェクト自体も、そもそも不安定な状況で……","ENG":"Back then, even the Titan Project itself was still uncertain.","TWN":"更何況當時連泰坦計畫都不明確。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그러니까… 체르노프 박사님께서는…….","JPN":"だから……チェルノフ博士は……","ENG":"So of course... Dr. Chernov–","TWN":"所以……切爾諾夫博士才……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 틀렸네.","JPN":"いや、違う。","ENG":"No. You're mistaken.","TWN":"不，錯了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"체르노프 박사는 자네 팀이 고안한 주피터 플랜을 폐기하지 않았어.","JPN":"チェルノフ博士は君のチームが考案したジュピタープランを破棄していない。","ENG":"Dr. Chernov never discarded the Jupiter Plan your team conceived.","TWN":"切爾諾夫博士並沒有放棄你們團隊設計的木星計畫。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오히려 훗날 다가올 미래를 위해, 지금껏 그 히스토리를 간직하고 있었지.","JPN":"いずれ来る未来のために、その記録を取っておいたのさ。","ENG":"On the contrary, he preserved that history for the future that would one day arrive.","TWN":"而是為了將來有一天能夠實現，他一直保留著那段歷史。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"퓨처 앳 워의 설립 이념에 따라서…….","JPN":"フューチャーアットウォーの設立理念に従い……","ENG":"In keeping with the founding ideals of Future-at-War...","TWN":"是基於天啟兵器的創立理念……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 자신의 소중한 제자를 위해서 말이지.","JPN":"そして、自分の大切な弟子のためにね。","ENG":"And for the sake of a cherished pupil.","TWN":"也是因為自己看重的徒弟。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"뭐라고……?","JPN":"何だと……？","ENG":"What...?","TWN":"你說什麼……？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"헛소리하지 마! 박사님은 분명 그때 내 눈앞에서 주피터 플랜의 연구 노트를……","JPN":"戯言を！　博士は確かにあの時、私の目の前でジュピタープランの研究ノートを……","ENG":"Don't spout nonsense! I saw it with my own eyes as he tore up the Jupiter Plan research notes!","TWN":"別胡說！博士當時明明就在我眼前把木星計畫的研究筆記……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ANASTASIA_COFFIN_NULL_NULL","text":{"KOREA":"오랜만에 터프가이가 불러줘서 단숨에 날아왔건만…….","JPN":"タフガイから久々に連絡が来たから、駆けつけて来たけど……","ENG":"Called here in a rush by our so-called tough guy... and what do I find?","TWN":"那傢伙難得找我，虧我還立刻飛奔過來……"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANASTASIA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"ANASTASIA_COFFIN_NULL_NULL","text":{"KOREA":"설마, 그게 하필 아버지와 관련된, 귀찮은 일일 줄은 몰랐는데 말이지……?","JPN":"まさかお父さんに関わる厄介事だったとはねぇ……？","ENG":"Of course it has to be a troublesome matter tied to my father.","TWN":"結果沒想到偏偏是和父親有關的麻煩事……？"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANASTASIA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"너는……?","JPN":"あなたは……？","ENG":"You are...?","TWN":"你是……？"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANASTASIA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ANASTASIA_COFFIN_NULL_NULL","text":{"KOREA":"설마, 그 연구 노트라는 게, 이걸 말하는 건 아니겠지?","JPN":"その研究ノートって、もしかしてこれのことかしら。","ENG":"Surely you don't mean... this research note, do you?","TWN":"難道，你說的研究筆記，就是這個嗎？"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANASTASIA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L11_1","type":"dialog","speaker":"ANASTASIA_COFFIN_NULL_NULL","text":{"KOREA":"그라운드 원 시니어 님?","JPN":"グラウンド・ワンのシニアさん？","ENG":"Ground One Senior?","TWN":"G1的Senior？"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANASTASIA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"아나스타샤… 체르노바……?","JPN":"アナスタシア……チェルノワ……？","ENG":"Anastasia... Chernova...?","TWN":"安娜斯塔莎……？"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANASTASIA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"네가 코핀에 입사했다는 건 알고 있었어.","JPN":"あなたがコフィンに入社したことは知っていた。","ENG":"I knew you'd joined Coffin.","TWN":"我知道你加入了科芬公司。"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하지만 네가 어째서 여길……?","JPN":"しかし、なぜあなたがここに……？","ENG":"But what on earth are you doing here...?","TWN":"但是你為什麼會在這裡……？"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"르네 양, 내가 말했을 텐데?","JPN":"ルネ君、言ったはずだ。","ENG":"Renée, I told you before.","TWN":"芮妮，我應該說過吧？"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내 모든 인력을 최대한 동원해서, 이 사태를 대비하고 있다고.","JPN":"私はできる限りの人員を動員し、この事態に備えていると。","ENG":"I am mobilizing every resource to prepare for what's coming.","TWN":"我正在動用我所有的人力來應對這個事態。"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 자네 역시 나를 도와준다고 하지 않았나?","JPN":"そして君も私に協力すると言っていなかったか？","ENG":"And did you not agree to assist me?","TWN":"而且你不也是說要幫我嗎？"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리에게 남은 시간은 그리 많지 않아.","JPN":"私たちに残された時間はそう多くない。","ENG":"Time is not on our side.","TWN":"我們時間不多了。"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"캄파멘토 측에 파견된 인원으로부터 이미 그곳 상황을 전달받았어.","JPN":"カンパメント側に派遣した人員から、そちらの状況を伝えてもらった。","ENG":"My agents dispatched to Campamento have already sent word of the situation there.","TWN":"我從派遣到坎帕門托的人那裡得知到那邊的情況。"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"천공 대균열로 인해, 그곳 일대에 매우 강력한 반중력장이 형성되었다고 하더군.","JPN":"天空大亀裂により、一帯に非常に強力な反重力場が形成されたらしい。","ENG":"They report that the Celestial Grand Dimension Crevice above has generated an intense anti-gravity field.","TWN":"由於天空大峽谷的影響，那一帶形成非常強大的反重力場域域。"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"파견된 인원을 구하기 위해선, 특수한 기체가 필요할 거야.","JPN":"派遣した人員を救出するためには、特殊な機体が必要だろう。","ENG":"To extract them, a specialized craft will be required.","TWN":"為了救出派遣的人員，需要特殊的機體。"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"반중력 필드를 극복하기 위해서는 똑같이 반중력 필드로 상쇄하는 수밖에 없어.","JPN":"同じ反重力フィールドで相殺する以外、反重力フィールドを克服できる術はない。","ENG":"The only way to counter an anti-gravity field is with another anti-gravity field of equal strength.","TWN":"為了克服反重力場域，只能用同樣的反重力場域來抵消。"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하지만 대균열 단위의 반중력 필드를 상쇄시킬 수 있는 기체가…….","JPN":"しかし、大亀裂規模の反重力フィールドを相殺できるほどの機体は……","ENG":"But a craft that could offset a Grand Dimension Crevice-level field...?","TWN":"但是能夠抵消大峽谷單位的反重力場域的機體……"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"설마, 당신……?","JPN":"あなた、まさか……？","ENG":"No... don't tell me...","TWN":"難道，你……？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"지금… 전략 공중 요새 <color=#ffd34c>히페리온</color>을 말하는 거야……?","JPN":"今……戦略空中要塞<color=#ffd34c>ハイペリオン</color>のことを言っているのか……？","ENG":"You mean... the strategic aerial fortress <color=#ffd34c>Hyperion</color>...?","TWN":"現在……你是在說戰略空中要塞<color=#ffd34c>海柏利昂</color>嗎……？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};